macro.edw.star_sum.macro_sql:
{% macro star_sum(from, relation_alias=False, except=[], prefix='', suffix='') -%}
    {#-- Prevent querying of db in parsing mode. This works because this macro does not create any new refs. #}
    {%- if not execute -%}
        {{ return('*') }}
    {% endif %}

    {% set cols = dbt_utils.get_filtered_columns_in_relation(from, except) %}

    {%- if cols|length <= 0 -%}
      {{- return('*') -}}
    {%- else -%}
        {%- for col in cols %}
            sum({%- if relation_alias %}{{ relation_alias }}.{% else %}{%- endif -%}{{ adapter.quote(col)|trim}}) as {{ adapter.quote(prefix ~ col ~ suffix)|trim }}
            {%- if not loop.last %},{{ '\n  ' }}{% endif %}
        {%- endfor -%}
    {% endif %}
{%- endmacro %}

