macro.edw.abc_item_group.macro_sql:
{% macro abc_item_group(alias='ei') %}
    {% set hvac_abc_group = ('Air Filters', 'EcoFi Boost', 'EcoFi System Refresh', 'EcoFi System Rejuvenation', 'Iwave-R Residential Air Purifier',
                             'EcoFi Boost Heating', 'EcoFi System Refresh Heating', 'EcoFi System Rejuvenation-Heat') %}
    {% set plumbing_abc_group = ('') %}
    {% set sewer_abc_group = ('') %}
    {% set electric_abc_group = ('') %}
    CASE 
        -- Will add other groups when we the ABC items have been determined
        WHEN {{ alias }}.item_name in {{ hvac_abc_group }} then 'HVAC'
        --WHEN {{ alias }}.item_name in {{ plumbing_abc_group }} then 'Plumbing'
        --WHEN {{ alias }}.item_name in {{ sewer_abc_group }} then 'Sewer'
        --WHEN {{ alias }}.item_name in {{ electric_abc_group }} then 'Electric'
        ELSE NULL
    END
{% endmacro %}

